const input = $input.first().json;
const action = input.action || 'html_to_pdf';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.pdf-mcp&cred_key=eq.pdfmcp_api_key&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'pdf-mcp.io API key not configured. Use add_credential to set it up.' } }];
}

const apiKey = creds[0].cred_value;
const API_BASE = 'https://api.pdf-mcp.io';
const apiHeaders = {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json'
};

// === html_to_pdf ===
if (action === 'html_to_pdf') {
  const html = input.html;
  if (!html) return [{ json: { error: 'Parameter "html" is required (HTML content to convert).' } }];

  try {
    const body = {
      html: html,
      storage: { mode: 'default' }
    };
    if (input.css) body.css = input.css;
    if (input.filename) body.filename = input.filename;

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/htmlToPdf',
      headers: apiHeaders,
      body: JSON.stringify(body),
      returnFullResponse: true,
      json: false
    });

    let result;
    try {
      result = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
    } catch(e) {
      result = resp.body;
    }

    if (result && result.url) {
      let msg = 'PDF generated successfully!';
      msg += '\nDownload: ' + result.url;
      if (result.document_id) msg += '\nDocument ID: ' + result.document_id;
      if (result.pages) msg += '\nPages: ' + result.pages;
      return [{ json: { result: msg, url: result.url, document_id: result.document_id } }];
    } else if (result && result.document_id) {
      const fileResp = await helpers.httpRequest({
        method: 'GET',
        url: API_BASE + '/files/' + result.document_id,
        headers: apiHeaders
      });
      let msg = 'PDF generated successfully!';
      if (fileResp.url) msg += '\nDownload: ' + fileResp.url;
      msg += '\nDocument ID: ' + result.document_id;
      return [{ json: { result: msg, url: fileResp.url || '', document_id: result.document_id } }];
    } else {
      return [{ json: { result: 'PDF generated (binary response). Use storage mode for a download link.', raw: String(result).substring(0, 200) } }];
    }
  } catch (err) {
    return [{ json: { error: 'Failed to generate PDF: ' + err.message } }];
  }

// === extract_text ===
} else if (action === 'extract_text') {
  const pdfUrl = input.pdf_url;
  if (!pdfUrl) return [{ json: { error: 'Parameter "pdf_url" is required (URL of the PDF to extract text from).' } }];

  try {
    const body = { pdf_url: pdfUrl };
    if (input.pages) body.pages = input.pages;

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/extractText',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    let result = 'Text extracted from PDF';
    if (resp.total_pages) result += ' (' + resp.total_pages + ' pages)';
    result += ':\n\n';
    if (resp.text) {
      result += resp.text.substring(0, 3000);
      if (resp.text.length > 3000) result += '\n\n... (truncated, ' + resp.text.length + ' chars total)';
    } else if (resp.pages && Array.isArray(resp.pages)) {
      for (const p of resp.pages.slice(0, 10)) {
        result += '--- Page ' + p.page + ' ---\n' + (p.text || '').substring(0, 500) + '\n\n';
      }
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to extract text: ' + err.message } }];
  }

// === merge_pdfs ===
} else if (action === 'merge_pdfs') {
  const urls = input.pdf_urls;
  if (!urls) return [{ json: { error: 'Parameter "pdf_urls" is required (comma-separated PDF URLs).' } }];

  try {
    const urlList = urls.split(',').map(u => u.trim()).filter(u => u);
    if (urlList.length < 2) return [{ json: { error: 'At least 2 PDF URLs are needed to merge.' } }];

    const body = {
      pdfs_url: urlList,
      storage: { mode: 'default' }
    };
    if (input.filename) body.filename = input.filename;

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/mergePdfs',
      headers: apiHeaders,
      body: JSON.stringify(body),
      returnFullResponse: true,
      json: false
    });

    let result;
    try {
      result = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
    } catch(e) {
      result = resp.body;
    }

    if (result && result.url) {
      return [{ json: { result: 'PDFs merged successfully!\nDownload: ' + result.url, url: result.url } }];
    } else if (result && result.document_id) {
      const fileResp = await helpers.httpRequest({
        method: 'GET',
        url: API_BASE + '/files/' + result.document_id,
        headers: apiHeaders
      });
      return [{ json: { result: 'PDFs merged!\nDownload: ' + (fileResp.url || result.document_id), url: fileResp.url || '' } }];
    } else {
      return [{ json: { result: 'PDFs merged (binary response).', raw: String(result).substring(0, 200) } }];
    }
  } catch (err) {
    return [{ json: { error: 'Failed to merge PDFs: ' + err.message } }];
  }

// === list_files ===
} else if (action === 'list_files') {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/files?limit=20',
      headers: apiHeaders
    });

    const docs = resp.documents || resp.data || [];
    if (docs.length === 0) {
      return [{ json: { result: 'No stored PDF files found.' } }];
    }

    let result = 'Stored PDFs (' + docs.length + '):\n\n';
    for (const d of docs) {
      result += '- ' + (d.filename || d.id) + ' (ID: ' + d.id + ')';
      if (d.pages) result += ' — ' + d.pages + ' pages';
      if (d.created_at) result += ' — ' + d.created_at.substring(0, 10);
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list files: ' + err.message } }];
  }

// === get_file ===
} else if (action === 'get_file') {
  const docId = input.document_id;
  if (!docId) return [{ json: { error: 'Parameter "document_id" is required.' } }];

  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/files/' + docId + '?expires_in=3600',
      headers: apiHeaders
    });

    let result = 'File: ' + (resp.filename || docId);
    if (resp.url) result += '\nDownload: ' + resp.url;
    if (resp.pages) result += '\nPages: ' + resp.pages;
    if (resp.created_at) result += '\nCreated: ' + resp.created_at;
    result += '\nLink valid for 1 hour.';

    return [{ json: { result, url: resp.url || '' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get file: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use html_to_pdf, extract_text, merge_pdfs, list_files, or get_file.' } }];
}
